('lockbit', 'LockBit', '{"LockBit Black","LockBit 3.0","LockBit 4.0"}', 'Russia / Eastern Europe', 'Prolific ransomware-as-a-service operation responsible for the highest volume of ransomware attacks globally. Known for rapid encryption, double extortion, and affiliate program.', '{"healthcare","finance","manufacturing","government","education"}', '2019', '2024-10-15', '{"Ransomware-as-a-Service","Double Extortion","RDP Exploitation","Phishing","Intermittent Encryption"}'),
('volt-typhoon', 'Volt Typhoon', '{"BRONZE SILHOUETTE","Vanguard Panda","DEV-0391"}', 'China', 'Chinese state-sponsored threat actor focused on pre-positioning within US critical infrastructure. Notable for exclusive use of living-off-the-land techniques to avoid detection.', '{"energy","telecommunications","government","manufacturing"}', '2021', '2024-10-10', '{"Living-off-the-Land","VPN Exploitation","SOHO Router Compromise","Credential Harvesting","Long-term Persistence"}'),
