-- Seed articles
insert into articles (title, slug, summary, content, threat_level, category, cves, affected_products, threat_actors, industries, attack_vector, source, source_url, published_at, updated_at, discovered_at, exploited_at, patched_at, verified, verified_by, tags, region) values
('Critical RCE Vulnerability in Cisco IOS XE Actively Exploited in the Wild', 'critical-rce-cisco-ios-xe-exploited', 'A critical remote code execution vulnerability (CVSS 10.0) in Cisco IOS XE is being actively exploited by threat actors to gain persistent access to enterprise network infrastructure. Over 40,000 devices confirmed compromised.', 'Cisco has disclosed a critical zero-day vulnerability in IOS XE that allows unauthenticated remote attackers to create privileged accounts on affected systems. The vulnerability, tracked as CVE-2024-20198, carries the maximum CVSS score of 10.0. Threat intelligence indicates that a sophisticated threat actor has been exploiting this vulnerability since at least September 2024, deploying implants on compromised devices to maintain persistent access. Organizations using Cisco IOS XE should immediately check for indicators of compromise and apply the available patches. The Cybersecurity and Infrastructure Security Agency (CISA) has added this vulnerability to its Known Exploited Vulnerabilities catalog.', 'critical', 'zero-day', '{"CVE-2024-20198","CVE-2024-20199"}', '{"Cisco IOS XE","Cisco Catalyst Switches","Cisco ASR Routers"}', '{"UNC-CISCO-1"}', '{"telecommunications","government","finance","technology"}', 'Network / HTTP/HTTPS Web UI', 'Cisco PSIRT', 'https://sec.cloudapps.cisco.com/security/center', '2024-10-16T14:00:00Z', '2024-10-17T09:30:00Z', '2024-09-28T00:00:00Z', '2024-09-28T00:00:00Z', '2024-10-22T00:00:00Z', true, '{"CISA","Cisco PSIRT"}', '{"zero-day","network-infrastructure","active-exploitation"}', 'Global'),

('LockBit 4.0 Ransomware Targets Healthcare Systems with New Encryption Engine', 'lockbit-4-ransomware-healthcare', 'LockBit ransomware group has deployed version 4.0 with an advanced encryption engine specifically targeting healthcare infrastructure. Multiple hospital systems in the US and EU have been impacted.', 'The LockBit ransomware group has released version 4.0 of their ransomware-as-a-service platform, featuring a redesigned encryption engine that specifically targets healthcare management systems and electronic health record databases. At least 12 hospital networks across the United States and European Union have reported incidents in the past 72 hours. The new variant employs intermittent encryption combined with data exfiltration, significantly reducing encryption time while maximizing data theft. FBI and CISA have issued a joint advisory recommending healthcare organizations implement network segmentation and maintain offline backups.', 'critical', 'ransomware', '{}', '{"Epic EHR","Cerner Millennium","Windows Server 2019/2022"}', '{"LockBit"}', '{"healthcare"}', 'Phishing / RDP Exploitation', 'FBI / CISA Joint Advisory', 'https://www.cisa.gov/news-events/cybersecurity-advisories', '2024-10-15T18:00:00Z', '2024-10-16T12:00:00Z', '2024-10-13T00:00:00Z', '2024-10-13T00:00:00Z', null, true, '{"FBI","CISA","HHS"}', '{"ransomware","healthcare","data-exfiltration"}', 'North America / Europe'),

('APT29 Deploys Novel Backdoor via Microsoft Teams Phishing Campaign', 'apt29-microsoft-teams-phishing-backdoor', 'Russian state-sponsored threat actor APT29 (Cozy Bear) has been observed using Microsoft Teams phishing messages to deploy a previously unseen backdoor targeting government and diplomatic organizations.', 'Microsoft Threat Intelligence has identified a campaign by APT29 leveraging compromised Microsoft 365 tenants to send phishing messages through Microsoft Teams. The messages contain lures related to diplomatic communications and, when interacted with, deploy a novel backdoor dubbed TeamSpy that uses Microsoft Graph API for command-and-control communications. The backdoor blends in with legitimate Teams traffic, making detection extremely difficult. Targeted organizations include foreign ministries, think tanks, and defense contractors across NATO member states.', 'high', 'apt', '{}', '{"Microsoft Teams","Microsoft 365","Windows 10/11"}', '{"APT29"}', '{"government","defense"}', 'Phishing / Microsoft Teams', 'Microsoft Threat Intelligence', 'https://www.microsoft.com/en-us/security/blog', '2024-10-14T10:00:00Z', '2024-10-15T08:00:00Z', '2024-10-10T00:00:00Z', null, null, true, '{"Microsoft","CISA"}', '{"apt","state-sponsored","phishing","backdoor"}', 'Europe / NATO'),

('Critical Authentication Bypass in FortiOS Allows Complete Network Takeover', 'fortios-authentication-bypass-critical', 'Fortinet has patched a critical authentication bypass vulnerability in FortiOS that allows remote attackers to gain super-admin access to affected firewalls. Exploitation in the wild confirmed.', 'A critical authentication bypass vulnerability in Fortinet FortiOS (CVE-2024-47575) allows unauthenticated attackers to gain super-admin privileges on affected devices via crafted HTTP requests to the management interface. Fortinet has confirmed active exploitation and urges immediate patching. The vulnerability affects FortiOS versions 7.0 through 7.4 and FortiProxy versions 7.0 through 7.4. Mandiant has linked exploitation activity to a China-nexus threat actor tracked as UNC3886, which has historically targeted network edge devices.', 'critical', 'vulnerability', '{"CVE-2024-47575"}', '{"FortiOS 7.0-7.4","FortiProxy 7.0-7.4","FortiGate Firewalls"}', '{"UNC3886"}', '{"government","finance","energy","telecommunications"}', 'Network / HTTP Management Interface', 'Fortinet PSIRT', 'https://www.fortiguard.com/psirt', '2024-10-12T16:00:00Z', '2024-10-14T11:00:00Z', '2024-10-05T00:00:00Z', '2024-10-08T00:00:00Z', '2024-10-12T00:00:00Z', true, '{"CISA","Fortinet PSIRT","Mandiant"}', '{"firewall","network-edge","authentication-bypass"}', 'Global'),

('Massive Supply Chain Attack Compromises npm Package with 12M Weekly Downloads', 'npm-supply-chain-attack-12m-downloads', 'A popular npm package with over 12 million weekly downloads was compromised via a hijacked maintainer account, injecting credential-stealing malware into builds for over 48 hours.', 'Security researchers have identified a supply chain attack targeting a widely-used npm utility package. The attacker gained access to a maintainer account through credential reuse and published malicious versions that exfiltrated environment variables, API keys, and database credentials to an attacker-controlled server. The compromised versions were live for approximately 48 hours before detection. Organizations using the package are advised to rotate all credentials that may have been exposed and audit their dependency trees. npm has revoked the compromised versions.', 'high', 'supply-chain', '{"CVE-2024-48901"}', '{"npm ecosystem","Node.js applications"}', '{}', '{"technology"}', 'Supply Chain / Package Repository', 'GitHub Security Advisory', 'https://github.com/advisories', '2024-10-11T22:00:00Z', '2024-10-12T14:00:00Z', '2024-10-11T18:00:00Z', null, null, true, '{"GitHub","npm Security"}', '{"supply-chain","npm","credential-theft"}', 'Global'),

('Chinese APT Group Volt Typhoon Targets US Water Infrastructure', 'volt-typhoon-us-water-infrastructure', 'Volt Typhoon has been observed targeting US water treatment facilities using living-off-the-land techniques, pre-positioning for potential disruption of critical infrastructure.', 'A joint advisory from CISA, NSA, and FBI warns that Chinese state-sponsored threat actor Volt Typhoon has expanded its targeting to include US water and wastewater treatment facilities. The group uses living-off-the-land binaries (LOLBins) to maintain persistent access while evading detection. Intelligence suggests the activity is focused on pre-positioning for potential disruptive attacks rather than immediate espionage. Affected facilities have been notified and are working with federal agencies to remediate the intrusions.', 'high', 'apt', '{}', '{"SCADA Systems","Operational Technology Networks","Windows Server"}', '{"Volt Typhoon"}', '{"energy","government"}', 'Living-off-the-Land / VPN Exploitation', 'CISA / NSA / FBI Joint Advisory', 'https://www.cisa.gov/news-events/cybersecurity-advisories', '2024-10-10T15:00:00Z', '2024-10-11T10:00:00Z', '2024-09-15T00:00:00Z', null, null, true, '{"CISA","NSA","FBI"}', '{"critical-infrastructure","state-sponsored","pre-positioning"}', 'United States'),

('Ivanti Connect Secure Zero-Day Chain Allows Unauthenticated RCE', 'ivanti-connect-secure-zero-day-chain', 'Two chained zero-day vulnerabilities in Ivanti Connect Secure VPN appliances enable unauthenticated remote code execution. Mass exploitation detected affecting thousands of organizations.', 'Ivanti has disclosed two zero-day vulnerabilities in Connect Secure (formerly Pulse Secure) VPN appliances that, when chained together, allow unauthenticated attackers to execute arbitrary commands on affected devices. CVE-2024-21887 is a command injection vulnerability, and CVE-2024-21888 is an authentication bypass. Volexity and Mandiant have observed mass exploitation by multiple threat actors, including suspected Chinese state-sponsored groups. Ivanti has released mitigation guidance while permanent patches are being developed.', 'critical', 'zero-day', '{"CVE-2024-21887","CVE-2024-21888"}', '{"Ivanti Connect Secure","Ivanti Policy Secure"}', '{"UTA0178"}', '{"government","defense","technology","finance"}', 'Network / VPN Appliance', 'Mandiant / Volexity', 'https://www.mandiant.com/resources/blog', '2024-10-09T12:00:00Z', '2024-10-11T09:00:00Z', '2024-10-01T00:00:00Z', '2024-10-01T00:00:00Z', null, true, '{"CISA","Mandiant","Volexity"}', '{"zero-day","vpn","mass-exploitation"}', 'Global'),

('Major US Financial Institution Discloses Breach Affecting 4.6M Customers', 'us-financial-institution-breach-4m', 'A top-10 US bank has disclosed a data breach impacting 4.6 million customers after attackers exploited a third-party file transfer vulnerability to exfiltrate sensitive financial data.', 'A major US financial institution has disclosed that a data breach originating from the exploitation of a MOVEit Transfer vulnerability exposed personal and financial data of approximately 4.6 million customers. The compromised data includes names, Social Security numbers, account numbers, and transaction histories. The breach occurred in May 2024 but was only detected in August after law enforcement notification. The institution is offering credit monitoring services and has implemented additional security controls around file transfer operations.', 'high', 'data-breach', '{"CVE-2023-34362"}', '{"MOVEit Transfer","Progress Software"}', '{"Cl0p"}', '{"finance"}', 'Web Application / File Transfer', 'SEC Filing / Institution Disclosure', 'https://www.sec.gov/cgi-bin/browse-edgar', '2024-10-08T09:00:00Z', '2024-10-09T16:00:00Z', '2024-08-15T00:00:00Z', '2024-05-28T00:00:00Z', null, true, '{"SEC","FBI"}', '{"data-breach","financial","moveit"}', 'United States'),

('QakBot Malware Returns with Advanced Evasion After FBI Takedown', 'qakbot-malware-returns-advanced-evasion', 'QakBot malware has resurfaced with significantly enhanced anti-analysis and evasion capabilities, just months after the FBI-led takedown of its botnet infrastructure.', 'Despite the FBI successful takedown of the QakBot botnet infrastructure in August 2023, the malware has returned with a substantially redesigned codebase. The new variant features advanced sandbox detection, encrypted C2 communications using DNS-over-HTTPS, and a modular architecture that loads malicious components only in memory. Distribution is occurring through phishing campaigns leveraging hijacked email threads. The resurgence demonstrates the resilience of cybercriminal operations and the challenges of permanent disruption.', 'medium', 'malware', '{}', '{"Windows 10/11","Microsoft Office"}', '{}', '{"finance","manufacturing","technology"}', 'Phishing / Email Thread Hijacking', 'Zscaler ThreatLabz', 'https://www.zscaler.com/blogs/security-research', '2024-10-07T11:00:00Z', '2024-10-08T08:00:00Z', '2024-10-03T00:00:00Z', null, null, true, '{"Zscaler","Microsoft"}', '{"malware","botnet","evasion"}', 'Global'),

('Google Chrome V8 Type Confusion Enables Sandbox Escape', 'chrome-v8-type-confusion-sandbox-escape', 'A type confusion vulnerability in Google Chrome V8 JavaScript engine allows full sandbox escape and arbitrary code execution. Emergency update released.', 'Google has released an emergency update for Chrome to address a critical type confusion vulnerability in the V8 JavaScript engine (CVE-2024-49123). The vulnerability allows an attacker to escape the Chrome sandbox and execute arbitrary code on the underlying system via a specially crafted web page. Google Threat Analysis Group has confirmed the vulnerability is being exploited in targeted attacks against journalists and political dissidents. All Chromium-based browsers are affected and users should update immediately.', 'high', 'vulnerability', '{"CVE-2024-49123"}', '{"Google Chrome","Microsoft Edge","Chromium-based browsers"}', '{}', '{"technology"}', 'Web / Malicious Website', 'Google Threat Analysis Group', 'https://blog.google/threat-analysis-group', '2024-10-06T20:00:00Z', '2024-10-07T10:00:00Z', '2024-10-04T00:00:00Z', '2024-10-04T00:00:00Z', '2024-10-06T00:00:00Z', true, '{"Google TAG"}', '{"browser","sandbox-escape","targeted-attacks"}', 'Global'),

('BlackCat Ransomware Affiliates Pivot to New RaaS Platform Cicada3301', 'blackcat-affiliates-cicada3301-raas', 'Former BlackCat/ALPHV ransomware affiliates have migrated to a new ransomware-as-a-service platform dubbed Cicada3301, featuring Rust-based payloads and advanced ESXi targeting.', 'Following the exit scam by BlackCat/ALPHV operators in March 2024, former affiliates have regrouped under a new ransomware-as-a-service platform called Cicada3301. The platform features Rust-based ransomware payloads with specific modules for targeting VMware ESXi environments and Linux systems. Initial access is typically gained through exploitation of VPN appliances and phishing. At least 30 organizations across multiple sectors have been listed on the group leak site in the past month.', 'medium', 'ransomware', '{}', '{"VMware ESXi","Linux Servers","Windows Server"}', '{"Cicada3301"}', '{"manufacturing","retail","healthcare","education"}', 'VPN Exploitation / Phishing', 'Group-IB Threat Intelligence', 'https://www.group-ib.com/blog', '2024-10-05T14:00:00Z', '2024-10-06T09:00:00Z', '2024-09-20T00:00:00Z', null, null, true, '{"Group-IB"}', '{"ransomware","raas","esxi"}', 'Global'),

('Critical SAP NetWeaver Flaw Exposes Enterprise Systems to Pre-Auth RCE', 'sap-netweaver-pre-auth-rce', 'A critical pre-authentication remote code execution vulnerability in SAP NetWeaver Application Server affects an estimated 50,000 enterprise systems worldwide.', 'SAP has released an emergency patch for a critical vulnerability in NetWeaver Application Server (CVE-2024-50001) that allows unauthenticated attackers to execute arbitrary commands on affected systems. The vulnerability exists in the Internet Communication Manager (ICM) component and can be exploited via specially crafted HTTP requests. Given that SAP NetWeaver underpins critical business processes in many large enterprises, the potential impact is severe. SAP is urging customers to apply the patch immediately and recommends implementing additional network segmentation as a defense-in-depth measure.', 'critical', 'vulnerability', '{"CVE-2024-50001"}', '{"SAP NetWeaver AS","SAP S/4HANA","SAP ERP"}', '{}', '{"manufacturing","finance","energy","retail"}', 'Network / HTTP', 'SAP Security Response', 'https://support.sap.com/en/my-support/knowledge-base/security-notes-news.html', '2024-10-04T08:00:00Z', '2024-10-05T12:00:00Z', '2024-09-25T00:00:00Z', null, '2024-10-04T00:00:00Z', true, '{"SAP"}', '{"enterprise","pre-auth","sap"}', 'Global');
